// Simple API client - API URL can be overridden for remote monitoring deployments.
const DEFAULT_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:3001';
const OFFLINE_SALES_QUEUE_KEY = 'pharmapos_offline_sales_queue_v1';

const syncListeners = new Set();

function normalizeBaseUrl(url) {
  return (url || '').trim().replace(/\/+$/, '');
}

function emitSyncStatus(status) {
  for (const listener of syncListeners) {
    try {
      listener(status);
    } catch (_) {
      // ignore listener errors to avoid breaking sync flow
    }
  }
}

function readOfflineSalesQueue() {
  if (typeof window === 'undefined') return [];
  const raw = window.localStorage.getItem(OFFLINE_SALES_QUEUE_KEY);
  if (!raw) return [];
  try {
    const parsed = JSON.parse(raw);
    return Array.isArray(parsed) ? parsed : [];
  } catch (_) {
    return [];
  }
}

function writeOfflineSalesQueue(queue) {
  if (typeof window === 'undefined') return;
  window.localStorage.setItem(OFFLINE_SALES_QUEUE_KEY, JSON.stringify(queue));
  emitSyncStatus({ pending: queue.length, syncing: false });
}

function createExternalId() {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }
  return `offline-${Date.now()}-${Math.random().toString(16).slice(2, 10)}`;
}

function enqueueOfflineSale(payload) {
  const queue = readOfflineSalesQueue();
  const entry = {
    id: createExternalId(),
    payload,
    created_at: new Date().toISOString(),
    attempts: 0,
    last_error: null,
  };
  queue.push(entry);
  writeOfflineSalesQueue(queue);
  return entry;
}

export function getApiBaseUrl() {
  const override = typeof window !== 'undefined'
    ? window.localStorage.getItem('pharmapos_api_url')
    : '';
  return normalizeBaseUrl(override) || DEFAULT_BASE_URL;
}

export function setApiBaseUrl(url) {
  const value = normalizeBaseUrl(url);
  if (typeof window === 'undefined') return DEFAULT_BASE_URL;
  if (value) window.localStorage.setItem('pharmapos_api_url', value);
  else window.localStorage.removeItem('pharmapos_api_url');
  return getApiBaseUrl();
}

export function getPendingSalesSyncCount() {
  return readOfflineSalesQueue().length;
}

export function subscribeToSyncStatus(listener) {
  syncListeners.add(listener);
  listener({ pending: getPendingSalesSyncCount(), syncing: false });
  return () => syncListeners.delete(listener);
}

async function request(method, path, body = null) {
  const opts = {
    method,
    headers: {},
  };
  if (body) {
    opts.headers['Content-Type'] = 'application/json';
    opts.body = JSON.stringify(body);
  }

  let res;
  try {
    res = await fetch(`${getApiBaseUrl()}${path}`, opts);
  } catch (_) {
    const error = new Error('Unable to reach the API. Check your network or API URL.');
    error.code = 'NETWORK';
    throw error;
  }

  let data = null;
  const contentType = res.headers.get('content-type') || '';
  if (contentType.includes('application/json')) {
    data = await res.json();
  } else {
    const text = await res.text();
    data = text ? { error: text } : {};
  }

  if (!res.ok) {
    const error = new Error(data.error || `Request failed: ${res.status}`);
    error.code = 'HTTP';
    error.status = res.status;
    throw error;
  }

  return data;
}

export async function syncPendingSales({ maxItems = 25 } = {}) {
  const initialQueue = readOfflineSalesQueue();
  if (initialQueue.length === 0) {
    emitSyncStatus({ syncing: false, pending: 0, synced: 0, failed: 0 });
    return { synced: 0, failed: 0, remaining: 0 };
  }

  emitSyncStatus({ syncing: true, pending: initialQueue.length, synced: 0, failed: 0 });

  const queue = [...initialQueue];
  let synced = 0;
  let failed = 0;
  let processed = 0;

  for (let i = 0; i < queue.length && processed < maxItems; i += 1, processed += 1) {
    const entry = queue[i];
    try {
      await request('POST', '/sales', {
        ...entry.payload,
        external_id: entry.payload.external_id || entry.id,
      });
      queue.splice(i, 1);
      i -= 1;
      synced += 1;
      emitSyncStatus({ syncing: true, pending: queue.length, synced, failed });
    } catch (error) {
      if (error.code === 'NETWORK') {
        break;
      }
      failed += 1;
      entry.attempts = (entry.attempts || 0) + 1;
      entry.last_error = error.message;
      emitSyncStatus({ syncing: true, pending: queue.length, synced, failed, lastError: error.message });
    }
  }

  writeOfflineSalesQueue(queue);
  emitSyncStatus({ syncing: false, pending: queue.length, synced, failed });
  return { synced, failed, remaining: queue.length };
}

export const api = {
  // Products
  getProducts: (params = {}) => {
    const qs = new URLSearchParams(params).toString();
    return request('GET', `/products${qs ? `?${qs}` : ''}`);
  },
  getProduct: (id) => request('GET', `/products/${id}`),
  createProduct: (data) => request('POST', '/products', data),
  updateProduct: (id, data) => request('PUT', `/products/${id}`, data),
  deleteProduct: (id) => request('DELETE', `/products/${id}`),
  getCategories: () => request('GET', '/products/categories/list'),

  // Batches
  getBatches: (productId) => request('GET', `/batches/${productId}`),
  createBatch: (data) => request('POST', '/batches', data),
  updateBatch: (id, data) => request('PUT', `/batches/${id}`, data),
  deleteBatch: (id) => request('DELETE', `/batches/${id}`),

  // Sales
  createSale: async (data) => {
    const payload = {
      ...data,
      external_id: data.external_id || createExternalId(),
    };

    try {
      return await request('POST', '/sales', payload);
    } catch (error) {
      if (error.code !== 'NETWORK') throw error;

      const queued = enqueueOfflineSale(payload);
      return {
        queued_offline: true,
        pending_sync_count: getPendingSalesSyncCount(),
        sale: {
          id: `OFFLINE-${queued.id.slice(0, 8)}`,
          date: new Date().toISOString(),
          external_id: payload.external_id,
          discount_type: payload.discount_type || null,
        },
        items: [],
        change: 0,
      };
    }
  },
  getSales: (params = {}) => {
    const qs = new URLSearchParams(params).toString();
    return request('GET', `/sales${qs ? `?${qs}` : ''}`);
  },
  getSale: (id) => request('GET', `/sales/${id}`),
  getHealth: () => request('GET', '/health'),

  // Reports
  getDailyReport: (date) => request('GET', `/reports/daily${date ? `?date=${date}` : ''}`),
  getInventoryReport: () => request('GET', '/reports/inventory'),
  getExpiringReport: (days = 30) => request('GET', `/reports/expiring?days=${days}`),

  // CSV exports (download link)
  getCsvUrl: (type, params = {}) => {
    const qs = new URLSearchParams(params).toString();
    return `${getApiBaseUrl()}/reports/${type}/csv${qs ? `?${qs}` : ''}`;
  },
};
